## Step-by-step Deobfuscation

The code uses a common JavaScript obfuscation pattern with:
1. A string array (`a0_0x4453`) containing base64-encoded strings
2. A decoder function (`a0_0x305b`) that decodes and caches strings
3. A self-executing shuffler that rearranges the string array
4. Hex number literals and mangled variable names

## Fully Deobfuscated Code

```javascript
// Constants
const TAU = 6.283;          // ~2π
const PHI = 1.618;          // Golden ratio
const SQRT1_2 = 0.707;      // ~√(1/2)

// Physics/simulation configuration
const config = {
    repulsionStrength: 4000,
    frictionCoeff: 0.004,
    amplitudeDamping: 0.92,
    dispersal: 0.0003,
    streamMax: 40,
    viscosity: 0.04,
    lerp: 0.06
};

// Define 6 graph nodes with positions, radii, and velocities
const nodes = [
    { id: "hub",     label: "Hub",     r: 26, x: 400, y: 300, vx: 0, vy: 0 },
    { id: "alpha",   label: "Alpha",   r: 16, x: 500, y: 200, vx: 0, vy: 0 },
    { id: "beta",    label: "Beta",    r: 16, x: 300, y: 400, vx: 0, vy: 0 },
    { id: "gamma",   label: "Gamma",   r: 14, x: 250, y: 180, vx: 0, vy: 0 },
    { id: "delta",   label: "Delta",   r: 14, x: 550, y: 380, vx: 0, vy: 0 },
    { id: "epsilon", label: "Epsilon", r: 12, x: 350, y: 150, vx: 0, vy: 0 }
];

// Define 8 spring connections (edges) between nodes
const edges = [
    { a: "hub",   b: "alpha",   rest: 160, k: 0.006 },
    { a: "hub",   b: "beta",    rest: 160, k: 0.005 },
    { a: "hub",   b: "gamma",   rest: 170, k: 0.004 },
    { a: "hub",   b: "delta",   rest: 170, k: 0.004 },
    { a: "hub",   b: "epsilon", rest: 180, k: 0.003 },
    { a: "alpha", b: "beta",    rest: 200, k: 0.002 },
    { a: "gamma", b: "delta",   rest: 220, k: 0.002 },
    { a: "alpha", b: "epsilon", rest: 200, k: 0.002 }
];

// Camera/viewport state with smooth interpolation
let camera = { x: 400, y: 300, zoom: 1 };
let cameraTarget = { x: 400, y: 300, zoom: 1 };

// Particle stream array
let particles = [];
let frameCount = 0;

// Helper: find a node by ID
function findNode(id) {
    for (let i = 0; i < nodes.length; i++) {
        if (nodes[i].id === id) return nodes[i];
    }
    return null;
}

// PHYSICS: Apply forces to all nodes
function applyForces() {
    // 1. Repulsion between every pair of nodes (Coulomb-like)
    for (let i = 0; i < nodes.length; i++) {
        for (let j = i + 1; j < nodes.length; j++) {
            let dx = nodes[i].x - nodes[j].x;
            let dy = nodes[i].y - nodes[j].y;
            let dist = Math.sqrt(dx * dx + dy * dy) || 1;
            let force = config.repulsionStrength / (dist * dist);
            let fx = (dx / dist) * force;
            let fy = (dy / dist) * force;
            nodes[i].vx += fx;
            nodes[i].vy += fy;
            nodes[j].vx -= fx;
            nodes[j].vy -= fy;
        }
    }

    // 2. Spring attraction along edges (Hooke's law)
    for (let i = 0; i < edges.length; i++) {
        let nodeA = findNode(edges[i].a);
        let nodeB = findNode(edges[i].b);
        if (!nodeA || !nodeB) continue;
        let dx = nodeB.x - nodeA.x;
        let dy = nodeB.y - nodeA.y;
        let dist = Math.sqrt(dx * dx + dy * dy) || 1;
        let displacement = dist - edges[i].rest;
        let force = (edges[i].k || config.frictionCoeff) * displacement;
        nodeA.vx += (dx / dist) * force;
        nodeA.vy += (dy / dist) * force;
        nodeB.vx -= (dx / dist) * force;
        nodeB.vy -= (dy / dist) * force;
    }

    // 3. Centering gravity + velocity damping + position update
    for (let i = 0; i < nodes.length; i++) {
        nodes[i].vx += (400 - nodes[i].x) * config.dispersal;
        nodes[i].vy += (300 - nodes[i].y) * config.dispersal;
        nodes[i].vx *= config.amplitudeDamping;
        nodes[i].vy *= config.amplitudeDamping;
        nodes[i].x += nodes[i].vx;
        nodes[i].y += nodes[i].vy;
    }
}

// PARTICLES: Spawn a new particle from a random node
function spawnParticle() {
    if (particles.length >= config.streamMax) return;
    let node = nodes[Math.floor(Math.random() * nodes.length)];
    let angle = Math.random() * TAU;
    let speed = 0.3 + Math.random() * SQRT1_2;
    particles.push({
        x: node.x,
        y: node.y,
        vx: Math.cos(angle) * speed,
        vy: Math.sin(angle) * speed,
        age: 0,
        maxAge: 800 + Math.random() * 1200,
        size: 0.8 + Math.random() * PHI * SQRT1_2
    });
}

// PARTICLES: Update all particles (move, drag, age, cull)
function updateParticles() {
    for (let i = particles.length - 1; i >= 0; i--) {
        let p = particles[i];
        p.vx *= 1 - config.viscosity * 0.125;
        p.vy *= 1 - config.viscosity * 0.125;
        p.x += p.vx;
        p.y += p.vy;
        p.age++;
        if (p.age > p.maxAge) particles.splice(i, 1);
    }
}

// CAMERA: Smoothly interpolate camera toward target
function updateCamera() {
    camera.x += (cameraTarget.x - camera.x) * config.lerp;
    camera.y += (cameraTarget.y - camera.y) * config.lerp;
    camera.zoom += (cameraTarget.zoom - camera.zoom) * config.lerp;
}

// MAIN LOOP: runs every 16ms (~60fps)
function tick() {
    applyForces();
    frameCount++;
    updateParticles();
    if (frameCount % 3 === 0) spawnParticle();
    updateCamera();
}

setInterval(tick, 16);
```

## What It Does

This is a **force-directed graph simulation engine** — the physics backend for a network/graph visualization:

### Core Mechanics

| System | Description |
|--------|-------------|
| **Node Repulsion** | All nodes push each other apart (inverse-square law, like electric charges) |
| **Spring Edges** | Connected nodes are pulled together via Hooke's law springs with rest lengths |
| **Centering Gravity** | A weak force pulls all nodes toward center point (400, 300) |
| **Velocity Damping** | Velocities are multiplied by 0.92 each frame to prevent runaway oscillation |
| **Particle Stream** | Decorative particles spawn from random nodes, drift outward, and die after a random lifespan |
| **Smooth Camera** | Camera position/zoom lerps toward a target (likely controlled by user interaction elsewhere) |

### The Graph Structure

```
        Epsilon
        /    \
    Alpha --- Beta
      \     /
       Hub
      /   \
  Gamma   Delta
```

A **hub-and-spoke** topology with a central "Hub" node (largest, r=26) connected to 5 satellite nodes, plus some cross-links between satellites.

### Summary

This is purely a **simulation/physics layer** with no rendering code — it would be paired with a Canvas or SVG renderer to draw the nodes, edges, and particles. It runs at ~60fps and produces a gently wobbling, organically-animated network graph with floating particle effects.
